#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        char *S = (char*)malloc(N+1);
        scanf("%s", S);
        int pairs = K/2;
        int extra = K%2;
        int prefixLen = pairs*3;
        int newLen = prefixLen + N;
        char *res = (char*)malloc(newLen+1);
        // fill prefix with '1'
        for(int i=0;i<prefixLen;i++) res[i]='1';
        // copy original string
        memcpy(res+prefixLen, S, N);
        res[newLen]='\0';
        if(extra){
            // find first "000" in original S
            for(int i=0;i+2<N;i++){
                if(S[i]=='0' && S[i+1]=='0' && S[i+2]=='0'){
                    int pos = prefixLen + i;
                    res[pos]='1'; res[pos+1]='1'; res[pos+2]='1';
                    break;
                }
            }
        }
        printf("%s\n", res);
        free(S);
        free(res);
    }
    return 0;
}

