const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const S = input[idx++];
  const pairs = Math.floor(K / 2);
  const extra = K % 2;
  const prefix = '1'.repeat(pairs * 3);
  let res = (prefix + S).split('');
  if (extra === 1) {
    for (let i = 0; i + 2 < N; i++) {
      if (S[i] === '0' && S[i + 1] === '0' && S[i + 2] === '0') {
        const pos = pairs * 3 + i;
        res[pos] = res[pos + 1] = res[pos + 2] = '1';
        break;
      }
    }
  }
  outputs.push(res.join(''));
}
